// Extract error details and conversation info
const execution = $input.first().json;
const error = execution.execution?.error || {};
const workflowName = execution.workflow?.name || 'Unknown';

// Try to find conversation_id from the execution data
let conversationId = null;
let contactId = null;
let accountId = null;

// Search through the execution data for Chatwoot info
const executionData = execution.execution?.data?.resultData?.runData || {};

for (const nodeName of Object.keys(executionData)) {
  const nodeRuns = executionData[nodeName];
  if (nodeRuns && nodeRuns[0]?.data?.main?.[0]) {
    for (const item of nodeRuns[0].data.main[0]) {
      if (item.json?.conversation?.id) {
        conversationId = item.json.conversation.id;
        accountId = item.json.account?.id || 1;
      }
      if (item.json?.sender?.id) {
        contactId = item.json.sender.id;
      }
      if (conversationId) break;
    }
  }
  if (conversationId) break;
}

return {
  json: {
    errorMessage: error.message || 'Unknown error',
    errorStack: error.stack || '',
    workflowName,
    conversationId,
    contactId,
    accountId: accountId || 1,
    timestamp: new Date().toISOString(),
    canNotify: !!conversationId
  }
};

// Log the error for debugging
console.error('=== LERAYSI ERROR ===');
console.error('Workflow:', $json.workflowName);
console.error('Error:', $json.errorMessage);
console.error('Conversation:', $json.conversationId || 'N/A');
console.error('Timestamp:', $json.timestamp);
console.error('Stack:', $json.errorStack);
console.error('=====================');

return $input.all();
